                        count: 0,
                        example_file: filename.clone(),
                        example_line: i + 1,
                        file_count: 0,
                        seen_files: Vec::new(),
                    });
                    group.count += 1;
                    if !group.seen_files.contains(&file_idx) {
                        group.seen_files.push(file_idx);
                        group.file_count += 1;
                    }
                }
            }
