                    });
                    group.count += 1;
                    if !group.seen_files.contains(&file_idx) {
                        group.seen_files.push(file_idx);
                        group.file_count += 1;
                        group.hits.push(ErrorHit {
                            path: path.display().to_string(),
                            line: 1,
                        });
                    }
                    if cli.list {
                        println!("{filename}: agent-meta (error)");
                    }
                }
            }
