        println!("Skipped:");
        for f in &skipped_files {
            println!("  {f}");
        }
        println!();
    }

    println!(
        "Summary: {processed} file(s), {total_records} records, {total_errors} errors{}",
        if total_skipped > 0 {
            format!(", {total_skipped} skipped")
        } else {
            String::new()
        },
    );

    if cli.strict && total_errors > 0 {
        std::process::exit(2);
    }
