            }
            for dir in &dirs {
                for fg in &file_globs {
                    let full = format!("{}/**/{fg}", dir.display());
                    match glob::glob(&full) {
                        Ok(paths) => {
                            for entry in paths.flatten() {
                                if entry.is_file() {
                                    files.push(entry);
                                }
                            }
                        }
                        Err(e) => {
