        println!("Empty:");
        for f in &empty_files {
            println!("  {f}");
        }
        println!();
    }

    let mut suffix = String::new();
    if total_skipped > 0 {
        suffix.push_str(&format!(", {total_skipped} skipped"));
    }
    if total_empty > 0 {
        suffix.push_str(&format!(", {total_empty} empty"));
    }
    println!("Summary: {processed} file(s), {total_records} records, {total_errors} errors{suffix}");

    if cli.strict && total_errors > 0 {
        std::process::exit(2);
    }
